{"path":"src/db.rs","content":"use crate::api::*;
use crate::distance::l2_distance;
use parking_lot::RwLock;
use std::sync::Arc;

pub struct VectorDB {
    data: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write();
        data.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut data = self.data.write();
        data.extend(vectors);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read();
        let mut results: Vec<SearchResult> = data
            .iter()
            .map(|(id, v)| SearchResult {
                id: *id,
                distance: l2_distance(vector, v),
            })
            .collect();

        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results.truncate(top_k as usize);
        results
    }
}
"}

{"content":"use std::arch::x86_64::*;

#[inline]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    f64::sqrt(l2_distance_squared(a, b) as f64)
}

#[inline]
pub fn l2_distance_squared(a: &[f32], b: &[f32]) -> f32 {
    unsafe {
        let mut sum = _mm512_setzero_ps();
        for i in (0..128).step_by(16) {
            let va = _mm512_loadu_ps(a.as_ptr().add(i));
            let vb = _mm512_loadu_ps(b.as_ptr().add(i));
            let diff = _mm512_sub_ps(va, vb);
            sum = _mm512_fmadd_ps(diff, diff, sum);
        }
        _mm512_reduce_add_ps(sum)
    }
}
