{"content":"use crate::api::*;
use crate::distance::l2_distance_squared;
use parking_lot::RwLock;
use std::sync::Arc;
use rayon::prelude::*;
use std::cmp::Ordering;

pub struct VectorDB {
    ids: RwLock<Vec<u64>>,
    vectors: RwLock<Vec<f32>>,
}

#[derive(Debug, Clone, Copy)]
struct DistanceId {
    distance_sq: f32,
    id: u64,
}

impl PartialEq for DistanceId {
    fn eq(&self, other: &Self) -> bool {
        self.distance_sq == other.distance_sq
    }
}

impl Eq for DistanceId {}

impl PartialOrd for DistanceId {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        self.distance_sq.partial_cmp(&other.distance_sq)
    }
}

impl Ord for DistanceId {
    fn cmp(&self, other: &Self) -> Ordering {
        self.partial_cmp(other).unwrap_or(Ordering::Equal)
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids = self.ids.write();
        let mut vectors = self.vectors.write();
        ids.push(id);
        vectors.extend(vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut ids = self.ids.write();
        let mut vectors_data = self.vectors.write();
        for (id, v) in vectors {
            ids.push(id);
            vectors_data.extend(v);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read();
        let vectors = self.vectors.read();
        let n = ids.len();

        let mut distances: Vec<DistanceId> = (0..n)
            .into_par_iter()
            .map(|i| {
                let start = i * 128;
                let v = &vectors[start..start + 128];
                DistanceId {
                    distance_sq: l2_distance_squared(query, v),
                    id: ids[i],
                }
            })
            .collect();

        distances.par_sort_unstable();

        distances.iter().take(top_k as usize).map(|d| SearchResult {
            id: d.id,
            distance: (d.distance_sq as f64).sqrt(),
        }).collect()
    }
}
